import React, { useEffect, useState } from "react";
import { Button, Space, Input, Card, Badge, Tooltip, Avatar } from "antd";
import { 
  BiEdit, 
  BiSearch, 
  BiStore, 
  BiPackage, 
  BiMap, 
  BiTrash,
  BiPlus,
  BiChevronRight,
  BiTransferAlt
} from "react-icons/bi";
import { AiFillDelete, AiOutlinePlus } from "react-icons/ai";
import { useDispatch, useSelector } from "react-redux";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { toast } from "react-toastify";
import {
  deleteStore,
  getEachUserStores,
  getStores,
  resetState,
} from "../../features/Store/StoreSlice";
import CustomModal from "../../components/CustomModal";
import { LayoutDashboard, Store, Package, Plus, Search, Trash2, Edit3, MapPin } from "lucide-react";

const ListStore = () => {
  const [open, setOpen] = useState(false);
  const [storeId, setStoreId] = useState("");
  const [searchText, setSearchText] = useState("");
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const storeState = useSelector((state) => state?.store?.stores);

  const basePath = location.pathname.includes("/superAdmin") ? "/superAdmin" : "/admin";

  const showModal = (e) => {
    setOpen(true);
    setStoreId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const deleteAStore = async (id) => {
    try {
      await dispatch(deleteStore(id)).unwrap();
      toast.success("Logistics Hub Terminated");
      const user = JSON.parse(localStorage.getItem("user"));
      if (user?.role === "admin" || user?.role === "superAdmin") {
        await dispatch(getStores());
      } else if (user && user._id) {
        await dispatch(getEachUserStores(user._id));
      }
    } catch (error) {
      toast.error("Hub Eviction Failed");
    } finally {
      hideModal();
    }
  };

  useEffect(() => {
    const fetchStores = async () => {
      const user = JSON.parse(localStorage.getItem("user"));
      if (user?.role === "admin" || user?.role === "superAdmin") {
        await dispatch(getStores());
      } else if (user && user._id) {
        await dispatch(getEachUserStores(user._id));
      }
    };
    fetchStores();
    dispatch(resetState());
  }, [dispatch]);

  const filteredStores =
    storeState?.filter(
      (s) =>
        !searchText ||
        s.storeName.toLowerCase().includes(searchText.toLowerCase()),
    ) || [];

  return (
    <div className="p-10 space-y-10 animate-in fade-in duration-700 bg-[#f8fafc] min-h-screen">
      {/* Header Section */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end gap-8 bg-white p-10 rounded-[40px] shadow-sm border border-slate-100">
        <div>
          <div className="flex items-center gap-3 mb-4">
              <div className="px-3 py-1 bg-blue-600 rounded-lg text-white font-black text-[10px] uppercase tracking-widest">
                  Network Assets
              </div>
              <div className="w-1.5 h-1.5 rounded-full bg-blue-500 animate-pulse" />
          </div>
          <h1 className="text-5xl font-black text-slate-900 tracking-tight leading-none">
            Hub <span className="text-blue-600">Registry</span>
          </h1>
          <p className="text-slate-500 font-bold text-lg mt-4 max-w-lg italic opacity-80">
            Real-time management of regional logistics nodes and distribution centers.
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-4 w-full lg:w-auto">
          <div className="relative group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-300 group-hover:text-blue-500 transition-colors" size={20} />
            <Input
              placeholder="Locate Node ID..."
              className="pl-12 pr-6 h-14 w-full sm:w-72 rounded-2xl border-2 border-slate-50 bg-slate-50/50 focus:bg-white focus:border-blue-500 transition-all font-bold text-slate-600"
              onChange={(e) => setSearchText(e.target.value)}
              bordered={false}
            />
          </div>
          <Link to={`${basePath}/Add-Store`} className="w-full sm:w-auto">
            <Button
              type="primary"
              size="large"
              className="bg-slate-900 border-none h-14 px-8 flex items-center justify-center gap-3 rounded-2xl font-black text-[12px] uppercase tracking-widest shadow-xl shadow-slate-900/10 hover:translate-y-[-2px] transition-all w-full"
            >
              <Plus size={18} /> Deploy Hub
            </Button>
          </Link>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8">
        {filteredStores.map((store) => (
          <Card
            key={store._id}
            hoverable
            className="group rounded-[40px] border-none shadow-sm hover:shadow-2xl hover:shadow-blue-500/5 transition-all duration-500 overflow-hidden bg-white"
            bodyStyle={{ padding: 0 }}
          >
            {/* Card Header/Banner */}
            <div className="h-32 bg-gradient-to-br from-slate-900 to-slate-800 p-8 relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_top_right,rgba(37,99,235,0.15),transparent)] pointer-events-none" />
                <BiStore size={80} className="absolute -right-4 -bottom-4 text-white/5 transform -rotate-12 group-hover:scale-110 transition-transform duration-700" />
                <div className="flex items-center gap-4 relative z-10">
                    <div className="w-12 h-12 rounded-xl bg-white/10 backdrop-blur-md border border-white/20 flex items-center justify-center text-white">
                        <Store size={22} />
                    </div>
                    <div>
                        <h4 className="text-white text-xl font-black tracking-tight truncate w-48">
                            {store.storeName}
                        </h4>
                        <div className="flex items-center gap-1.5 mt-1">
                            <div className="w-1.5 h-1.5 rounded-full bg-emerald-400 shadow-sm" />
                            <span className="text-[10px] font-black text-white/40 uppercase tracking-widest">Node Operational</span>
                        </div>
                    </div>
                </div>
            </div>

            <div className="p-8 space-y-8">
              <div className="space-y-4">
                <div className="flex items-start gap-4">
                    <div className="w-10 h-10 rounded-xl bg-slate-50 border border-slate-100 flex items-center justify-center text-slate-400">
                        <MapPin size={18} />
                    </div>
                    <div className="flex-1">
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none block mb-1">
                            Hub Coordinates
                        </span>
                        <p className="text-slate-600 font-bold text-[13px] leading-relaxed line-clamp-2 italic">
                            {store.address}
                        </p>
                    </div>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-50 flex items-center justify-between">
                <Link to={`${basePath}/list-store/store/${store._id}`}>
                  <Button
                    type="primary"
                    ghost
                    size="middle"
                    icon={<Package size={16} />}
                    className="rounded-xl border-blue-100 text-blue-600 font-black text-[11px] uppercase tracking-widest h-11 px-6 hover:bg-blue-600 hover:text-white transition-all"
                  >
                    Inventory
                  </Button>
                </Link>
                <div className="flex items-center gap-2">
                  <Tooltip title="Modify Logic">
                    <Link to={`${basePath}/list-Store/${store._id}`}>
                      <Button
                        type="text"
                        icon={<Edit3 size={18} />}
                        className="text-slate-400 hover:text-blue-600 hover:bg-blue-50 w-11 h-11 rounded-xl flex items-center justify-center"
                      />
                    </Link>
                  </Tooltip>
                  <Tooltip title="Decommission Node">
                    <Button
                      type="text"
                      danger
                      icon={<Trash2 size={18} />}
                      onClick={() => showModal(store._id)}
                      className="text-slate-400 hover:text-rose-600 hover:bg-rose-50 w-11 h-11 rounded-xl flex items-center justify-center"
                    />
                  </Tooltip>
                </div>
              </div>
            </div>
            
            {/* Footer Decorative Bar */}
            <div className="h-1.5 w-full bg-slate-100 group-hover:bg-blue-600 transition-colors" />
          </Card>
        ))}

        {filteredStores.length === 0 && (
          <div className="col-span-full py-32 text-center bg-white rounded-[60px] border-4 border-dashed border-slate-50">
            <div className="w-24 h-24 bg-slate-50 rounded-[40px] flex items-center justify-center mx-auto mb-8 border border-slate-100">
                <BiStore size={40} className="text-slate-200" />
            </div>
            <h3 className="text-slate-900 text-2xl font-black tracking-tight mb-2">No Registered Hubs</h3>
            <p className="text-slate-400 font-bold uppercase tracking-widest text-[11px]">
              Deploy your first logistics node to begin operations
            </p>
          </div>
        )}
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteAStore(storeId)}
        title="Protocol: Node Decommission"
        content="This will permanently disconnect the logistics node from the Pulse Addis global network. All associated physical assets and inventory must be reassigned before termination."
      />
    </div>
  );
};

export default ListStore;
